 1	import React, { FC } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { IoK8sApiBatchV1Job, IoK8sApiCoreV1ConfigMap } from '@kubevirt-ui/kubevirt-api/kubernetes';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
 7	import {
 8	  Breadcrumb,
 9	  BreadcrumbItem,
10	  Button,
11	  ButtonVariant,
12	  Flex,
13	  FlexItem,
14	  Title,
15	} from '@patternfly/react-core';
16	
17	import CheckupsStorageActions from '../components/CheckupsStorageActions';
18	
19	type CheckupsStorageDetailsPageHeaderProps = {
20	  configMap: IoK8sApiCoreV1ConfigMap;
21	  jobs: IoK8sApiBatchV1Job[];
22	};
23	
24	const CheckupsStorageDetailsPageHeader: FC<CheckupsStorageDetailsPageHeaderProps> = ({
25	  configMap,
26	  jobs,
27	}) => {
28	  const { t } = useKubevirtTranslation();
29	  const navigate = useNavigate();
30	  const [namespace] = useActiveNamespace();
31	
32	  return (
33	    <>
34	      <Breadcrumb className="pf-v6-c-breadcrumb co-breadcrumb">
35	        <BreadcrumbItem>
36	          <Button
37	            isInline
38	            onClick={() => navigate(`/k8s/ns/${namespace}/checkups/storage`)}
39	            variant={ButtonVariant.link}
40	          >
41	            {t('Storage checkup')}
42	          </Button>
43	        </BreadcrumbItem>
44	        <BreadcrumbItem>{t('Storage checkup details')}</BreadcrumbItem>
45	      </Breadcrumb>
46	      <Flex justifyContent={{ default: 'justifyContentSpaceBetween' }}>
47	        <Title className="co-section-heading" headingLevel="h2">
48	          {configMap?.metadata?.name}
49	        </Title>
50	        <FlexItem>
51	          <CheckupsStorageActions configMap={configMap} jobs={jobs} />
52	        </FlexItem>
53	      </Flex>
54	    </>
55	  );
56	};
57	
58	export default CheckupsStorageDetailsPageHeader;

